package com.i2i.voltwise.audit; import com.i2i.voltwise.home.Home; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.Instant; @Entity @Table(name="consumption_snapshots") public class ConsumptionSnapshot { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) public Long id; @ManyToOne(optional=false,fetch=FetchType.LAZY) @JoinColumn(name="home_id") public Home home; @Column(name="energy_kwh",nullable=false) public BigDecimal energyKwh; @Column(nullable=false) public BigDecimal cost; @Column(name="captured_at",nullable=false) public Instant capturedAt; protected ConsumptionSnapshot(){} public ConsumptionSnapshot(Home h,double kwh,double cost){home=h;energyKwh=BigDecimal.valueOf(kwh);this.cost=BigDecimal.valueOf(cost);capturedAt=Instant.now();} }
